steps.solution_code:
type StepState = 'locked' | 'active' | 'done';

export function stateLabel(state: StepState): string {
  switch (state) {
    case 'locked':
      return 'Locked';
    case 'active':
      return 'In progress';
    case 'done':
      return 'Completed';
    default: {
      const unreachable: never = state;
      return unreachable;
    }
  }
}
